// mm/src/store/workflowContext.js
import React, { createContext, useContext, useState } from 'react';

const WorkflowContext = createContext(null);

export const WorkflowProvider = ({ children }) => {
  // ----- Book details (Upload metadata stage) -----
  const [bookDetails, setBookDetails] = useState({
    title: '',
    author: '',
    category: '',
    subcategory: '',
  });

  // ----- Uploaded files -----
  const [manuscriptFiles, setManuscriptFiles] = useState([]);

  const addFile = (file) => {
    setManuscriptFiles((prev) => {
      // Replace by id if it already exists
      const others = prev.filter((f) => f.id !== file.id);
      return [...others, file];
    });
  };

  // ----- Generic preferences object (used in WorkflowContainer.hasProgress) -----
  const [preferences, setPreferences] = useState({});

  // ----- Upload phase: 'select' -> 'ready' -> 'metadata' -----
  const [uploadPhase, setUploadPhase] = useState('select');

  // ----- Design selections (Design step) -----
  const [design, setDesign] = useState({
    analyzed: false,
    stage: 'typography', // 'typography' | 'layout' | 'trim' | 'summary'
    typography: 'hybrid',
    layout: 'standard',
    trim: '6x9',
  });

  // ----- Step indicator for the workflow header -----
  const [currentStep, setCurrentStep] = useState(1);

  // ----- Raw manuscript text used by Preview step -----
  // This is populated in UploadStep when the user uploads a file.
  const [previewText, setPreviewText] = useState('');

  const value = {
    // book details
    bookDetails,
    setBookDetails,

    // files
    manuscriptFiles,
    addFile,

    // generic user / design preferences
    preferences,
    setPreferences,

    // upload-phase sub-wizard
    uploadPhase,
    setUploadPhase,

    // design selections
    design,
    setDesign,

    // step indicator
    currentStep,
    setCurrentStep,

    // text for preview
    previewText,
    setPreviewText,
  };

  return (
    <WorkflowContext.Provider value={value}>
      {children}
    </WorkflowContext.Provider>
  );
};

export const useWorkflow = () => {
  const ctx = useContext(WorkflowContext);
  if (!ctx) {
    throw new Error('useWorkflow must be used inside a WorkflowProvider');
  }
  return ctx;
};
